(window.webpackJsonp=window.webpackJsonp||[]).push([[240],{752:function(o,r,e){"use strict";e.r(r);var i=e(3),n=Object(i.a)({},(function(){var o=this,r=o.$createElement,e=o._self._c||r;return e("ContentSlotsDistributor",{attrs:{"slot-key":o.$parent.slotKey}},[e("p",[e("img",{attrs:{src:"http://img1.gtimg.com/tech/pics/hv1/242/146/1954/127096322.jpg",alt:""}})]),o._v(" "),e("p",[o._v("腾讯科技讯 10月30日消息，据外电报道，消息人士周四透露，Alphabet旗下子公司谷歌(微博)正筹划把PC操作系统Chrome与移动操作系统Android进行合并。此举表明移动计算已越来越占据主导地位。")]),o._v(" "),e("p",[o._v("消息人士称，为把这两款操作系统合并到一起，谷歌的技术人员已付出了近两年的辛劳工作。这项工作在日前取得了进展。据悉，谷歌计划在2017年正式推出合并版操作系统，而且该公司会在明年对外展示早期版的新款操作系统。")]),o._v(" "),e("p",[o._v("Android目前是全球应用最广泛的操作系统，支持了超过10亿部智能手机，以及由众多厂商开发的其它设备。作为一款PC操作系统，Chrome主要被Chromebook等笔记本电脑和台式机所采用。市场调研公司IDC的统计数据显示，Chrome仍只是PC操作系统市场的小众产品，份额尚不足3%。")]),o._v(" "),e("p",[o._v("消息人士称，谷歌将推出的新版Android操作系统同样也将支持PC，让用户能够进入目前提供了超100万款应用的应用商店Google Play。谷歌希望让搜索、YouTube等盈利服务进入更多的设备。该公司同样还希望迎合独立开发者的胃口，让他们的应用在微幅调整后就能够适用于更多的设备。")]),o._v(" "),e("p",[o._v("消息人士称，在谷歌的两款操作系统合并之后，Chromebook将会进行更名，但目前尚未确定名称。不过谷歌打算继续保留移动和PC浏览器Chrome的名称。")]),o._v(" "),e("p",[o._v("2009年曾负责Chrome操作系统开发工作的谷歌首席执行官桑达尔·皮查伊（Sundar Pichai），上周在财报电话会议中向分析师表示，“作为一种计算模式，移动计算最终将会同如今我们所认为的台式计算交融在一起。”")]),o._v(" "),e("p",[o._v("作为谷歌在操作系统市场的主要竞争对手之一，微软此前已采取了类似的做法。微软Windows 10操作系统能够同时支持PC和智能手机，并准许一些应用在两种设备中都可以运行。不过与微软的做法完全不同，苹果在操作系统的问题上仍坚持分而治之的立场：iOS面向智能手机和平板电脑，OS X面向Mac。苹果首席执行官蒂姆·库克（Tim Cook）上月曾表示，把两款操作系统进行合并“只会削弱它们的功能，用户无法得到最佳的体验。”")]),o._v(" "),e("p",[o._v("就谷歌而言，Android地位的提升与Chrome的消亡，代表着这家公司的重大转变。谷歌创办于网络时代，这家公司最初的服务依旧还在。谷歌之所以推出Chrome，目的是为了给搜索引擎服务带来更多的流量。谷歌白手起家开发了移动操作系统Android。在经历了一番内部争论之后，谷歌决定同时兼顾两款操作系统。不过随着移动设备和应用的逐渐流行，Android取得了巨大的成功。")]),o._v(" "),e("p",[o._v("市场此前曾一直预计谷歌的两款操作系统将会进行合并。在2013年Android联合创始人安迪·鲁宾（Andy Rubin）转任机器人项目负责人之后，皮查伊曾同时负责Chrome和Android业务。去年，皮查伊任命Android技术副总裁洛克海默（Hiroshi Lockheimer）兼任Chrome业务负责人。")]),o._v(" "),e("p",[o._v("今年9月，谷歌推出一款搭载Android操作系统的办公笔记本电脑Pixel C。这也是谷歌Pixel产品线中首款放弃使用Chrome操作系统的产品。去年，谷歌还让一些Android应用能够在Chromebook上运行。")]),o._v(" "),e("p",[o._v("Chrome和Android均基于Linux开源代码。不过消息人士称，由于两款操作系统有着重大区别，因此把两款操作系统合并到一起的工作并不轻松。")]),o._v(" "),e("p",[o._v("笔记本电脑拥有键盘，且拥有比移动设备更大的显示屏，因此用户经常同时使用多个应用程序，并在这些应用程序中相互传输内容。虽然Android智能手机和平板电脑也能够运行多个应用，但却无法同时展示在显示屏中。这也让用户在应用间进行切换变得十分困难。\nChromebook用户目前并没有太多可选择的应用，因为Chromebook的用户数量太少，应用开发者一直不太愿意为Chromebook开发应用。")]),o._v(" "),e("p",[o._v("Airbnb技术经理亚历克斯·戴维斯（Alex Davis）表示，“目前我们对为Chrome OS开发应用的兴趣不大，因为Chrome OS的市场规模相对较小。”戴维斯认为，对谷歌而言，把两款操作系统进行合并可能是正确的选择，因为Android已经无处不在。\n把Chrome融入到Android当中，能够让谷歌为自己的生产力应用Docs和Sheets等赢得更多的企业用户。因为同时兼顾着两款操作系统，目前这对谷歌而言还是一项挑战。（明轩）")])])}),[],!1,null,null,null);r.default=n.exports}}]);